const a = [
  {"id":4556,"text":"Which of the following amino acids is used for the formation of niacin?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 384.","responses":[{"text":"Glutamic acid","correct":false,"visible":false},{"text":"Tryptophan","correct":true,"visible":false},{"text":"Tyrosine","correct":false,"visible":false},{"text":"Glycine","correct":false,"visible":false},{"text":"Valine","correct":false,"visible":false}]},{"id":4569,"text":"The hexose monophosphate (HMP) shunt occurs in which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 145.","responses":[{"text":"Mitochondrion","correct":false,"visible":false},{"text":"Cytosol","correct":true,"visible":false},{"text":"Ribosome","correct":false,"visible":false},{"text":"Mitochondrial matrix","correct":false,"visible":false},{"text":"Endoplasmic reticulum","correct":false,"visible":false}]},{"id":4570,"text":"Which of the following is not supplied by the inferior mesenteric artery?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 598, 641.","responses":[{"text":"Anal canal below anal valve","correct":true,"visible":false},{"text":"Sigmoid colon","correct":false,"visible":false},{"text":"Lower part of the descending colon","correct":false,"visible":false},{"text":"Anal canal above anal valve","correct":false,"visible":false},{"text":"Distal one-third of transverse colon","correct":false,"visible":false}]},{"id":4577,"text":"What does the presence of hepatitis B surface antibodies in routine blood tests indicate?","explanation":null,"reference":"1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 832-833.\r\n\r\n2) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 120.","responses":[{"text":"No successful recovery from the infection","correct":false,"visible":false},{"text":"No vaccination to hepatitis B","correct":false,"visible":false},{"text":"Past infection only","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Past infection and vaccination to hepatitis B","correct":true,"visible":false}]},{"id":4580,"text":"Which of the following does not form the boundary of the caudate lobe of the liver?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 329, 330.","responses":[{"text":"Fissure for the inferior vena cava","correct":false,"visible":false},{"text":"Fissure for ligamentum teres","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Porta hepatis","correct":false,"visible":false},{"text":"Fissure for the ligamentum venosum","correct":false,"visible":false}]},{"id":4586,"text":"Which part of the salivary glands secretes saliva?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 329.","responses":[{"text":"Salivary ducts","correct":false,"visible":false},{"text":"Acini","correct":true,"visible":false},{"text":"Ciliated cells","correct":false,"visible":false},{"text":"Granules","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":4591,"text":"Which of the following controls the secretion of salivary glands?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 810.","responses":[{"text":"Vestibular nuclei","correct":false,"visible":false},{"text":"Vagal nucleus","correct":false,"visible":false},{"text":"Mesencephalic nucleus","correct":false,"visible":false},{"text":"Superior and inferior salivatory nuclei","correct":true,"visible":false},{"text":"Nucleus ambiguus","correct":false,"visible":false}]},{"id":4599,"text":"Which of the following causes most of the cases of peptic ulcer disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 766.","responses":[{"text":"Streptococcus pyogenes","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":false,"visible":false},{"text":"Helicobacter pylori","correct":true,"visible":false},{"text":"Haemophilus influenzae","correct":false,"visible":false}]},{"id":4600,"text":"Which of the following is not among the functions of the liver?","explanation":null,"reference":"Kalra A, Yetiskul E, Wehrle CJ, Tuma F. Physiology, liver. In: StatPearls. StatPearls Publishing; 2022. Accessed July 7, 2022. http://www.ncbi.nlm.nih.gov/books/NBK535438/","responses":[{"text":"Detoxification of chemicals","correct":false,"visible":false},{"text":"Bile production and secretion","correct":false,"visible":false},{"text":"Storage of glycogen, vitamins, and minerals","correct":false,"visible":false},{"text":"Metabolism of fats, proteins, and carbohydrates","correct":false,"visible":false},{"text":"Oxygenation of blood","correct":true,"visible":false}]},{"id":4607,"text":"Which of the following cancers is associated with helicobacter pylori?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 764.","responses":[{"text":"Mucosa-associated lymphoid tissue (MALT) lymphoma","correct":true,"visible":false},{"text":"Pancreatic carcinoma","correct":false,"visible":false},{"text":"Cervical carcinoma","correct":false,"visible":false},{"text":"Bladder carcinoma","correct":false,"visible":false},{"text":"Gallbladder cancer","correct":false,"visible":false}]},{"id":4608,"text":"Which of the following antacid is responsible for causing metabolic or systemic alkalosis?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 1089.","responses":[{"text":"Sodium bicarbonate","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Magnesium hydroxide","correct":false,"visible":false},{"text":"Aluminium hydroxide","correct":false,"visible":false},{"text":"Calcium carbonate","correct":false,"visible":false}]},{"id":4609,"text":"Which of the following statements is inappropriate about the stomach and intestine?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 310-311, 315, 317.","responses":[{"text":"Enteroendocrine cells present throughout the length of the small intestine","correct":false,"visible":false},{"text":"Paneth cells are present in the depths of intestinal glands","correct":false,"visible":false},{"text":"M (microfold) cells overlying the lymphoid follicles of Peyer patches","correct":false,"visible":false},{"text":"Mucous neck cells present in the deeper parts of gastric glands","correct":true,"visible":false},{"text":"Parietal (oxyntic) cells present throughout deeper parts of the gland","correct":false,"visible":false}]},{"id":4611,"text":"Which of the following is correct for the lysosomal storage diseases?","explanation":null,"reference":"Sun A. Lysosomal storage disease overview. Annals of Translational Medicine. Published December 2018. https://pubmed.ncbi.nlm.nih.gov/30740407/","responses":[{"text":"It occurs due to increased enzyme concentration","correct":false,"visible":false},{"text":"It occurs due to decrease in enzyme function","correct":true,"visible":false},{"text":"It occurs due to decreased lysosomes production","correct":false,"visible":false},{"text":"It occurs due to increased product degradation","correct":false,"visible":false},{"text":"It occurs due to increased lysosomes production","correct":false,"visible":false}]},{"id":4612,"text":"What is the most common cause of chronic gastritis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 763.","responses":[{"text":"Staphylococcus saprophyticus","correct":false,"visible":false},{"text":"Clostridium difficile","correct":false,"visible":false},{"text":"Helicobacter pylori","correct":true,"visible":false},{"text":"Escherichia coli","correct":false,"visible":false},{"text":"Vibrio cholerae","correct":false,"visible":false}]},{"id":4630,"text":"What is not a hallmark of malabsorption?","explanation":null,"reference":"Zuvarox T, Belletieri C. Malabsorption syndromes. In: StatPearls. StatPearls Publishing; 2022. Accessed July 7, 2022. http://www.ncbi.nlm.nih.gov/books/NBK553106/","responses":[{"text":"Foul-smelling stool","correct":false,"visible":false},{"text":"Weight gain","correct":true,"visible":false},{"text":"Floaty stool","correct":false,"visible":false},{"text":"Weight loss","correct":false,"visible":false},{"text":"Steatorrhea","correct":false,"visible":false}]},{"id":4631,"text":"The abdominal aorta descends anterior to which of the following vertebrae?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 343.","responses":[{"text":"T12-L4","correct":true,"visible":false},{"text":"T12-L5","correct":false,"visible":false},{"text":"L1-L4","correct":false,"visible":false},{"text":"T9-L4","correct":false,"visible":false},{"text":"L1-L5","correct":false,"visible":false}]},{"id":4632,"text":"Which of the following enzymes is involved both in glycolysis and gluconeogenesis?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 121.","responses":[{"text":"Phosphoglycerate kinase","correct":true,"visible":false},{"text":"Hexokinase","correct":false,"visible":false},{"text":"Phosphofructokinase-1","correct":false,"visible":false},{"text":"Pyruvate kinase","correct":false,"visible":false},{"text":"Phosphofructokinase-2","correct":false,"visible":false}]},{"id":4633,"text":"Which of the following ions is pumped into the intermembrane space from the matrix of the mitochondrion?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 77.","responses":[{"text":"H+ ion","correct":true,"visible":false},{"text":"Na+ ion","correct":false,"visible":false},{"text":"Ca+2 ion","correct":false,"visible":false},{"text":"K+ ion","correct":false,"visible":false},{"text":"Cl- ion","correct":false,"visible":false}]},{"id":4634,"text":"Which of the following molecules is needed for the conversion of fumarate into malate during the Krebs cycle?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 113.","responses":[{"text":"FADH₂","correct":false,"visible":false},{"text":"NADPH₂","correct":false,"visible":false},{"text":"H₂O","correct":true,"visible":false},{"text":"O₂","correct":false,"visible":false},{"text":"ATP","correct":false,"visible":false}]},{"id":4635,"text":"A patient reports symptoms of hepatic encephalopathy, slurring of speech, and blurring of vision. What are they most likely due to?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 257.","responses":[{"text":"Hyperammonemia","correct":true,"visible":false},{"text":"Ecstacy intoxication","correct":false,"visible":false},{"text":"Abdominal abcess","correct":false,"visible":false},{"text":"Homocystinuria","correct":false,"visible":false},{"text":"Alcohol intoxication","correct":false,"visible":false}]},{"id":4636,"text":"What is the preferred treatment of hyperammonemia?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 258.","responses":[{"text":"Give antiemetics","correct":false,"visible":false},{"text":"Increase protein in diet","correct":false,"visible":false},{"text":"Give antivirals","correct":false,"visible":false},{"text":"Limit protein in diet","correct":true,"visible":false},{"text":"Give antidiarrheals","correct":false,"visible":false}]},{"id":4637,"text":"Oxidative decarboxylation of alpha-ketoglutarate, during the Krebs cycle, is catalyzed by which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 112.","responses":[{"text":"Alpha-ketoglutarate dehydrogenase complex","correct":true,"visible":false},{"text":"Alpha-ketoglutarate synthase complex","correct":false,"visible":false},{"text":"Succinyl CoA synthase","correct":false,"visible":false},{"text":"Succinyl CoA dehydrogenase","correct":false,"visible":false},{"text":"Malate dehydrogenase","correct":false,"visible":false}]},{"id":4638,"text":"Which of the following is incorrect about tyrosine?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 261, 263, 284.","responses":[{"text":"Tyrosine is involved in the synthesis of catecholamines","correct":false,"visible":false},{"text":"End products of tyrosine are fumarate and oxaloacetate","correct":false,"visible":false},{"text":"It is a non-essential amino acid","correct":false,"visible":false},{"text":"Amino group of tyrosine is tryptamine","correct":true,"visible":false},{"text":"Tyrosine can be synthesized from phenylalanine","correct":false,"visible":false}]},{"id":4639,"text":"Liver glycogen decreases in which of the following conditions?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 329.","responses":[{"text":"High ATP concentration","correct":false,"visible":false},{"text":"Low adenosine monophosphate (AMP) concentration","correct":false,"visible":false},{"text":"Low glucagon levels","correct":false,"visible":false},{"text":"High insulin levels","correct":false,"visible":false},{"text":"Starvation","correct":true,"visible":false}]},{"id":4640,"text":"What set of lab values fit for hyperammonemia?","explanation":null,"reference":"(1) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 80.\r\n\r\n\r\n(2) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 256-257.","responses":[{"text":"Decreased α-ketoglutarate, increased glutamate and GABA","correct":false,"visible":false},{"text":"Decreased glutamate, GABA, α-ketoglutarate","correct":true,"visible":false},{"text":"Decreased GABA, increased glutamate and α-ketoglutarate","correct":false,"visible":false},{"text":"Increased glutamate, GABA, α-ketoglutarate","correct":false,"visible":false},{"text":"Decreased glutamate, increased GABA and α-ketoglutarate","correct":false,"visible":false}]},{"id":4641,"text":"The medial boundary of the femoral ring is formed by which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 713.","responses":[{"text":"Cooper's ligament","correct":false,"visible":false},{"text":"Lacunar ligament","correct":true,"visible":false},{"text":"Pectineal ligament","correct":false,"visible":false},{"text":"Iliopectineal ligament","correct":false,"visible":false},{"text":"Inguinal ligament","correct":false,"visible":false}]},{"id":4662,"text":"Which of the following is not drained by portal vein?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 451.","responses":[{"text":"Abdominal part of the alimentary canal (except the anus)","correct":false,"visible":false},{"text":"Spleen","correct":false,"visible":false},{"text":"Kidney","correct":true,"visible":false},{"text":"Gall bladder","correct":false,"visible":false},{"text":"Pancreas","correct":false,"visible":false}]},{"id":4668,"text":"Which of the following is not present in the space of Disse?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 339.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Blood plasma","correct":false,"visible":false},{"text":"Liver sinusoidal endothelial cells","correct":false,"visible":false},{"text":"Hepatic stellate cells","correct":false,"visible":false},{"text":"Kupffer cells","correct":true,"visible":false}]},{"id":4686,"text":"What is the normal pH of saliva?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 809.","responses":[{"text":"7.0-8.0","correct":false,"visible":false},{"text":"7.1-7.9","correct":false,"visible":false},{"text":"8.0-9.0","correct":false,"visible":false},{"text":"6.0-7.0","correct":true,"visible":false},{"text":"5.0-7.0","correct":false,"visible":false}]},{"id":4687,"text":"Which of the following is the normal serum bilirubin concentration?","explanation":null,"reference":"1) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 284.\r\n\r\n2) Arora V, Kulkarni RK, Cherian S, Pillai R, Shivali M. Hyperbilirubinemia in normal healthy donors. Asian Journal of Transfusion Science. Published July 2009. Accessed July 8, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2920475/","responses":[{"text":"1.0-2.0 mg/dl","correct":false,"visible":false},{"text":"2.0-3.0 mg/dl","correct":false,"visible":false},{"text":"0.1-1.2 mg/dl","correct":true,"visible":false},{"text":"3.0-4.0 mg/dl","correct":false,"visible":false},{"text":"1.2-2.5 mg/dl","correct":false,"visible":false}]},{"id":4688,"text":"In the cytosol, HMG CoA synthase (3-hydroxy-3-methyl-glutaryl-CoA synthase) is involved in the synthesis of which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 220.","responses":[{"text":"Ketone bodies","correct":false,"visible":false},{"text":"Cholesterol","correct":true,"visible":false},{"text":"Glycerol","correct":false,"visible":false},{"text":"Triacylglycerols (TAGs)","correct":false,"visible":false},{"text":"Pyruvate","correct":false,"visible":false}]},{"id":4689,"text":"HMG-CoA reductase (3-hydroxy-3-methyl-glutaryl-CoA reductase) activity is increased by which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 223.","responses":[{"text":"Glucocorticoids","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Insulin","correct":true,"visible":false},{"text":"Epinephrine","correct":false,"visible":false}]},{"id":4709,"text":"Which of the following drugs largely suppresses gastric acid secretion?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 542-543.","responses":[{"text":"Misoprostol","correct":false,"visible":false},{"text":"Bismuth subsalicylate","correct":false,"visible":false},{"text":"Ranitidine","correct":false,"visible":false},{"text":"Omeprazole","correct":true,"visible":false},{"text":"Atropine","correct":false,"visible":false}]},{"id":4726,"text":"Which of the following arteries is most likely to bleed in the duodenal ulcer?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 105.","responses":[{"text":"Superior pancreaticoduodenal artery","correct":false,"visible":false},{"text":"Left gastric artery","correct":false,"visible":false},{"text":"Gastroduodenal artery","correct":true,"visible":false},{"text":"Inferior pancreaticoduodenal artery","correct":false,"visible":false},{"text":"Superior mesenteric artery","correct":false,"visible":false}]},{"id":4745,"text":"Misoprostol is effective against which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 544.","responses":[{"text":"Alcoholic hematemesis","correct":false,"visible":false},{"text":"Aphthous mouth ulcers","correct":false,"visible":false},{"text":"NSAID-induced peptic ulcer","correct":true,"visible":false},{"text":"Vulvovaginitis","correct":false,"visible":false},{"text":"Henoch-Schonlein purpura","correct":false,"visible":false}]},{"id":4746,"text":"A boy presented to the outpatient department with the complaint of severe diarrhea. On examination, peristaltic waves were heard after every three seconds. How are these gut sounds classified?","explanation":null,"reference":"Innes JA, Dover AR, Fairhurst K, Macleod J, eds. Macleod’s Clinical Examination. 14th ed. Elsevier; 2018: 110.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Hypoactive","correct":false,"visible":false},{"text":"Hyperactive","correct":true,"visible":false},{"text":"Polarised","correct":false,"visible":false},{"text":"Absent","correct":false,"visible":false}]},{"id":4747,"text":"In smooth muscle, troponin is replaced by what protein?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 104.","responses":[{"text":"Myoglobin","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Dense bodies","correct":false,"visible":false},{"text":"Caveolae","correct":false,"visible":false},{"text":"Calmodulin","correct":true,"visible":false}]},{"id":4748,"text":"Which vessel does not drain directly into the portal vein?","explanation":null,"reference":"(1) Sharma M, Babu CSR, Garg S, Rai P. Portal venous system and its tributaries: a radial endosonographic assessment. Endoscopic Ultrasound. Published 2012. Accessed August 2, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4062210/\r\n\r\n\r\n(2) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 456, 501, 503.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Anterior inferior pancreaticoduodenal vein","correct":true,"visible":false},{"text":"Left gastric vein","correct":false,"visible":false},{"text":"Right gastric vein","correct":false,"visible":false},{"text":"Posterior superior pancreaticoduodenal vein","correct":false,"visible":false},{"text":"Cystic veins","correct":false,"visible":false}]},{"id":4749,"text":"What type of acini does the exocrine pancreas have?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 86.","responses":[{"text":"Mucous secretory unit","correct":false,"visible":false},{"text":"Seromucous secretory unit","correct":false,"visible":false},{"text":"Paracrine secretory unit","correct":false,"visible":false},{"text":"Serous secretory unit","correct":true,"visible":false},{"text":"Holocrine secretory unit","correct":false,"visible":false}]},{"id":4750,"text":"Which of the following enzymes is released most abundantly by the pancreas?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 815.","responses":[{"text":"Carboxypolypeptidase","correct":false,"visible":false},{"text":"Chymotrypsin","correct":false,"visible":false},{"text":"Amylase","correct":false,"visible":false},{"text":"Trypsin","correct":true,"visible":false},{"text":"Lipase","correct":false,"visible":false}]},{"id":4751,"text":"Which of the following hormones secreted by adipose tissue increases insulin sensitivity?","explanation":null,"reference":"Paz-Filho G, Mastronardi C, Wong ML, Licinio J. Leptin therapy, insulin sensitivity, and glucose homeostasis. Indian Journal of Endocrinology and Metabolism. Published December 2012. Accessed July 8, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3602983/","responses":[{"text":"Thyrotropin","correct":false,"visible":false},{"text":"Ghrelin","correct":false,"visible":false},{"text":"Leptin","correct":true,"visible":false},{"text":"Cholecystokinin","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false}]},{"id":4753,"text":"Which of the following statements is characteristic of indirect inguinal hernias?","explanation":null,"reference":"Chung KW, Chung HM, Halliday NL. BRS: Gross Anatomy. 8th ed. Wolters Kluwer Health; 2015: 108.","responses":[{"text":"Only passes through deep inguinal ring","correct":false,"visible":false},{"text":"Medial to inferior epigastric vessels","correct":false,"visible":false},{"text":"Anterior to spermatic cord","correct":false,"visible":false},{"text":"Posterior to spermatic cord","correct":false,"visible":false},{"text":"Lateral to inferior epigastric vessels","correct":true,"visible":false}]},{"id":4754,"text":"What type of gastritis presents with increased intraepithelial neutrophils and lymphoid aggregations deep into gastric tissue?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 764.","responses":[{"text":"Curling ulcer","correct":false,"visible":false},{"text":"Autoimmune gastritis","correct":false,"visible":false},{"text":"Cushing ulcer","correct":false,"visible":false},{"text":"NSAIDs associated gastritis","correct":false,"visible":false},{"text":"H. pylori gastritis","correct":true,"visible":false}]},{"id":4757,"text":"Brunner's glands are present in the submucosa layer of which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 317.","responses":[{"text":"Colon","correct":false,"visible":false},{"text":"Antrum of the stomach","correct":false,"visible":false},{"text":"Fundus of the stomach","correct":false,"visible":false},{"text":"Ileum","correct":false,"visible":false},{"text":"Esophagus","correct":false,"visible":false},{"text":"Duodenum","correct":true,"visible":false}]},{"id":4760,"text":"Which of the following nerves supplies the dermatome that is involved in referring the pain from the appendix to the umbilical region?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 48.","responses":[{"text":"5th cranial nerve","correct":false,"visible":false},{"text":"7th thoracic nerve","correct":false,"visible":false},{"text":"3rd cervical nerve","correct":false,"visible":false},{"text":"10th thoracic nerve","correct":true,"visible":false},{"text":"4th thoracic nerve","correct":false,"visible":false}]},{"id":4762,"text":"Which statement is incorrect about gallbladder histology?","explanation":null,"reference":"Laiq Hussain Siddiqui. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 203-204.","responses":[{"text":"Nerves and blood vessels in submucosa","correct":true,"visible":false},{"text":"Perimuscular dense connective tissue","correct":false,"visible":false},{"text":"No muscularis mucosa and submucosa","correct":false,"visible":false},{"text":"Thin smooth muscle oriented diagonally","correct":false,"visible":false},{"text":"Epithelium with folds","correct":false,"visible":false}]},{"id":4763,"text":"The epithelium of the esophagus has what function(s)?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 82, 305.","responses":[{"text":"Secretory only","correct":false,"visible":false},{"text":"Protective only","correct":false,"visible":false},{"text":"Absorptive only","correct":false,"visible":false},{"text":"Protective and absorptive","correct":false,"visible":false},{"text":"Protective and secretory","correct":true,"visible":false}]},{"id":4764,"text":"Which of the following hormones promotes stomach emptying?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 801.","responses":[{"text":"Secretin","correct":false,"visible":false},{"text":"Gastrin","correct":true,"visible":false},{"text":"Ghrelin","correct":false,"visible":false},{"text":"Cholecystokinin","correct":false,"visible":false},{"text":"Intrinsic factor","correct":false,"visible":false}]},{"id":4765,"text":"Which of the following structures contains columnar epithelium and intestinal glands?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 320.","responses":[{"text":"Colon","correct":true,"visible":false},{"text":"Stomach","correct":false,"visible":false},{"text":"Tongue","correct":false,"visible":false},{"text":"Esophagus","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":4766,"text":"A person presents with vomiting, nausea, upper abdominal discomfort, but no hematemesis. What is the most likely cause?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 763.","responses":[{"text":"Esophageal ulceration","correct":false,"visible":false},{"text":"Acute gastritis","correct":false,"visible":false},{"text":"Heart failure","correct":false,"visible":false},{"text":"Chronic gastritis","correct":true,"visible":false},{"text":"Hypertropic pyloric stenosis","correct":false,"visible":false}]},{"id":4769,"text":"Which ion is present in saliva to kill microbes?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 810.","responses":[{"text":"Pertechenate","correct":false,"visible":false},{"text":"Superoxide","correct":false,"visible":false},{"text":"Thiocyanate","correct":true,"visible":false},{"text":"Hydroxyl","correct":false,"visible":false},{"text":"Perchlorate","correct":false,"visible":false}]},{"id":4772,"text":"What is the function of lysozyme in saliva?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 810.","responses":[{"text":"Lubrication","correct":false,"visible":false},{"text":"Antimicrobial","correct":true,"visible":false},{"text":"Resist digestion","correct":false,"visible":false},{"text":"Epithelial protection","correct":false,"visible":false},{"text":"Bicarbonate ion secretion","correct":false,"visible":false}]},{"id":4774,"text":"What hormone stimulates the secretion of bicarbonate ions in the intestines?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 820.","responses":[{"text":"Secretin","correct":true,"visible":false},{"text":"Motilin","correct":false,"visible":false},{"text":"Cholecystokinin","correct":false,"visible":false},{"text":"Vasoactive intestinal peptide","correct":false,"visible":false},{"text":"Gastrin","correct":false,"visible":false}]},{"id":4776,"text":"The neck of the pancreas, where the portal vein is formed, is at the level of which vertebrae?","explanation":null,"reference":"GIT module; Anatomy lecture slides; Topic: Inferior vena cava and venous drainage of abdomen; Subtopic: Portal vein.","responses":[{"text":"L3","correct":false,"visible":false},{"text":"Between L2 and L3","correct":false,"visible":false},{"text":"L1","correct":false,"visible":false},{"text":"Between L1 and L2","correct":false,"visible":false},{"text":"L2","correct":true,"visible":false}]},{"id":4778,"text":"Which of the following structure has submucosal glands?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 326.","responses":[{"text":"Colon","correct":false,"visible":false},{"text":"Stomach","correct":false,"visible":false},{"text":"Cecum","correct":false,"visible":false},{"text":"Ileum","correct":false,"visible":false},{"text":"Duodenum","correct":true,"visible":false}]},{"id":4780,"text":"A gastrointestinal structure has longitudinal folds on its inner lining and submucosal glands are absent. What is this structure?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 307, 314.","responses":[{"text":"Rectum","correct":false,"visible":false},{"text":"Colon","correct":false,"visible":false},{"text":"Duodenum","correct":false,"visible":false},{"text":"Esophagus","correct":false,"visible":false},{"text":"Stomach","correct":true,"visible":false}]},{"id":4781,"text":"Which of the following is the source of the primary salivary secretion?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 809.","responses":[{"text":"Acini of parotid gland","correct":false,"visible":false},{"text":"Ducts of all major salivary glands","correct":false,"visible":false},{"text":"Acini of all salivary glands","correct":true,"visible":false},{"text":"Acini of submandibular gland","correct":false,"visible":false},{"text":"Parenchyma of all minor salivary glands","correct":false,"visible":false}]},{"id":4782,"text":"The bile salts are absorbed at which site of the gastrointestinal tract?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 225.","responses":[{"text":"Cecum","correct":false,"visible":false},{"text":"Jejunum","correct":false,"visible":false},{"text":"Proximal ileum","correct":false,"visible":false},{"text":"Duodenum","correct":false,"visible":false},{"text":"Terminal ileum","correct":true,"visible":false}]},{"id":4783,"text":"Meckel's diverticulum is usually formed at which site?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 231.","responses":[{"text":"Gastro-esophageal junction","correct":false,"visible":false},{"text":"Duodeno-jejunal junction","correct":false,"visible":false},{"text":"Ileo-cecal junction","correct":true,"visible":false},{"text":"Gastro-duodenal junction","correct":false,"visible":false},{"text":"Gastro-colic junction","correct":false,"visible":false}]},{"id":4784,"text":"A barium swallow test is done. Following the pylorus of the stomach, there is a triangular structure and a C-shaped loop. What is this structure?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 455, 463.","responses":[{"text":"Gastro-ileal junction","correct":false,"visible":false},{"text":"Duodenal cap","correct":true,"visible":false},{"text":"Fourth part of duodenum","correct":false,"visible":false},{"text":"Second part of duodenum","correct":false,"visible":false},{"text":"Third part of duodenum","correct":false,"visible":false}]},{"id":4793,"text":"A baby, after having his first feed, vomited it out and is having trouble breathing. What can this condition be?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 198.","responses":[{"text":"Esophageal atresia with tracheoesophageal fistula","correct":true,"visible":false},{"text":"Duodenal atresia","correct":false,"visible":false},{"text":"Tracheal occlusion with Meckel's diverticulum","correct":false,"visible":false},{"text":"Lung agenesis","correct":false,"visible":false},{"text":"Hypertrophic pyloric stenosis","correct":false,"visible":false}]},{"id":4794,"text":"Aluminum hydroxide impairs the absorption of which of the following?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 386.","responses":[{"text":"Cefoperazone","correct":false,"visible":false},{"text":"Erythromycin","correct":false,"visible":false},{"text":"Chloramphenicol","correct":false,"visible":false},{"text":"Tetracyclines","correct":true,"visible":false},{"text":"Penicillin","correct":false,"visible":false}]},{"id":4795,"text":"Which of the following is correct about the anatomical relation of the hernial sac in indirect inguinal hernia?","explanation":null,"reference":"1) Chung KW, Chung HM, Halliday NL. BRS: Gross Anatomy. 8th ed. Wolters Kluwer Health; 2015: 108.\r\n2) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 430, 435.","responses":[{"text":"Anterior to superficial inguinal ring","correct":false,"visible":false},{"text":"Medial to epigastric artery","correct":false,"visible":false},{"text":"Within the spermatic cord","correct":true,"visible":false},{"text":"Posterior to pubic tubercle","correct":false,"visible":false},{"text":"Medial to the deep inguinal ring","correct":false,"visible":false}]},{"id":4796,"text":"Where is HMG-CoA reductase (3-hydroxy-3-methyl-glutaryl-coenzyme A reductase) for cholesterol synthesis found in the cell?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 221.","responses":[{"text":"Cytosol","correct":true,"visible":false},{"text":"Mitochondria","correct":false,"visible":false},{"text":"Lysosome","correct":false,"visible":false},{"text":"Endoplasmic reticulum","correct":false,"visible":false},{"text":"Golgi body","correct":false,"visible":false}]},{"id":4797,"text":"Compliance of the patient is determined by which of the following?","explanation":null,"reference":"Honavar SG. Patient–physician relationship – Communication is the key. Indian Journal of Ophthalmology. Published November 2018. Accessed July 14, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6213668/","responses":[{"text":"Regimen of medication","correct":false,"visible":false},{"text":"Doctor-patient relationship","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Clinical setting","correct":false,"visible":false},{"text":"Skill of doctor","correct":false,"visible":false}]},{"id":4798,"text":"What is the first case of a communicable disease in a population called?","explanation":null,"reference":"GIT and liver module; Community medicine lecture slides; Topic: Dynamics of disease transmission; Subtopic: Disease transmission.","responses":[{"text":"Primary case","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Tertiary case","correct":false,"visible":false},{"text":"Secondary case","correct":false,"visible":false},{"text":"Index case","correct":false,"visible":false}]},{"id":4799,"text":"Which of the following enzymes is involved in the phosphorylation of glucose in the beta cells of the pancreas?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 979.","responses":[{"text":"Hexokinase","correct":false,"visible":false},{"text":"Glucokinase","correct":true,"visible":false},{"text":"Glucose-6-phosphatase","correct":false,"visible":false},{"text":"Phosphofructokinase","correct":false,"visible":false},{"text":"Glucose dehydrogenase","correct":false,"visible":false}]},{"id":4800,"text":"In smooth muscles, the cycling of myosin heads is slower than in skeletal muscles. What is the reason behind this?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 103.","responses":[{"text":"There are less actin molecules in smooth muscles","correct":false,"visible":false},{"text":"Myosin heads have less ATPase activity","correct":true,"visible":false},{"text":"There are more actin molecules in smooth muscles","correct":false,"visible":false},{"text":"Myosin heads have more ATPase activity","correct":false,"visible":false},{"text":"Myosin heads have no ATPase activity","correct":false,"visible":false}]},{"id":4801,"text":"Which of the following is required to stop contraction in smooth muscles?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 105.","responses":[{"text":"Calcium-calmodulin complex","correct":false,"visible":false},{"text":"Myosin light-chain phosphorylase","correct":false,"visible":false},{"text":"Myosin light-chain phosphatase","correct":true,"visible":false},{"text":"Active MLCK calcium-calmodulin chain complex","correct":false,"visible":false},{"text":"Myosin light-chain kinase","correct":false,"visible":false}]},{"id":4808,"text":"Cancer from the right breast can spread through lymph to the liver via lymph vessels draining which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 509.","responses":[{"text":"Ligamentum venosum","correct":false,"visible":false},{"text":"Groove for inferior vena cava","correct":false,"visible":false},{"text":"Bare area","correct":true,"visible":false},{"text":"Porta hepatis","correct":false,"visible":false},{"text":"Fossa for the gall bladder","correct":false,"visible":false}]},{"id":4809,"text":"Which of the following is the most common means of spread of hepatitis C in western countries?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 833-834.","responses":[{"text":"Intravenous drug abuse","correct":true,"visible":false},{"text":"Sexual contact","correct":false,"visible":false},{"text":"Transmission through health care workers","correct":false,"visible":false},{"text":"Blood transfusion","correct":false,"visible":false},{"text":"Tattoos","correct":false,"visible":false}]},{"id":4810,"text":"Pain in the back and infrascapular region due to gall stones is transmitted through which nerve roots?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 340.","responses":[{"text":"C1-C3","correct":false,"visible":false},{"text":"C2","correct":false,"visible":false},{"text":"C5-T1","correct":false,"visible":false},{"text":"C2-C5","correct":false,"visible":false},{"text":"C3-C5","correct":true,"visible":false}]},{"id":4811,"text":"The innervation for the cremasteric reflex originates from which of the following nerve roots?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 296.","responses":[{"text":"L1-L3","correct":false,"visible":false},{"text":"Below L2","correct":false,"visible":false},{"text":"Above L1","correct":false,"visible":false},{"text":"Between L1 and L2","correct":true,"visible":false},{"text":"Between L2 and L3","correct":false,"visible":false}]},{"id":4812,"text":"Which of the following drugs is recommended for the quickest treatment for ulcers?","explanation":null,"reference":"1) Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 1093.\r\n\r\n2) Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 543, 544.","responses":[{"text":"H2 antagonists","correct":false,"visible":false},{"text":"Antacid","correct":false,"visible":false},{"text":"Aspirin","correct":false,"visible":false},{"text":"Misoprostol","correct":false,"visible":false},{"text":"Omeprazole","correct":true,"visible":false}]},{"id":4813,"text":"A boy comes into the outpatient department with lactic acidosis. What is the cause of this condition?","explanation":null,"reference":"1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 365.\r\n\r\n\r\n2) Foucher CD, Tubben RE. Lactic acidosis. In: StatPearls. StatPearls Publishing; 2022. Accessed July 12, 2022. http://www.ncbi.nlm.nih.gov/books/NBK470202/","responses":[{"text":"Deficiency of enzymes in Krebs cycle","correct":false,"visible":false},{"text":"Too much lactase","correct":false,"visible":false},{"text":"Deficiency of lactase","correct":false,"visible":false},{"text":"Drinking too much milk","correct":false,"visible":false},{"text":"Too much anaerobic respiration","correct":true,"visible":false}]},{"id":4816,"text":"Where does the inferior vena cava drain into?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 390.","responses":[{"text":"Right atrium","correct":true,"visible":false},{"text":"Lumbar veins","correct":false,"visible":false},{"text":"Pulmonary veins","correct":false,"visible":false},{"text":"Posterior vena cava","correct":false,"visible":false},{"text":"Common iliac vein","correct":false,"visible":false}]},{"id":4820,"text":"Krebs cycle produces energy by which of the following means?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 113.","responses":[{"text":"By using electronegativity of electrons","correct":false,"visible":false},{"text":"By converting light energy to chemical energy","correct":false,"visible":false},{"text":"By generating ATP and electron carriers","correct":true,"visible":false},{"text":"By making electrons jump to higher energy levels","correct":false,"visible":false},{"text":"Through proton gradient","correct":false,"visible":false}]},{"id":4821,"text":"The Krebs cycle occurs only in mitochondria because of which of the following reasons?","explanation":null,"reference":"Alabduladhem TO, Bordoni B. Physiology, krebs cycle. In: StatPearls. StatPearls Publishing; 2022. Accessed July 12, 2022. http://www.ncbi.nlm.nih.gov/books/NBK556032/","responses":[{"text":"The pH of mitochondrial matrix is suitable for Krebs cycle","correct":false,"visible":false},{"text":"Mitochondria can withstand heat","correct":false,"visible":false},{"text":"Mitochondria are capable of self replication and have their own genes","correct":false,"visible":false},{"text":"Only the cells having mitochondria require Krebs cycle","correct":false,"visible":false},{"text":"The apparatus required for Krebs cycle is present only in mitochondria","correct":true,"visible":false}]},{"id":4822,"text":"Oxaloacetate regulates the Krebs cycle because of which of the following reasons?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 109.","responses":[{"text":"Its amount is regulated by malate dehydrogenase","correct":false,"visible":false},{"text":"It is also gluconeogenic","correct":false,"visible":false},{"text":"It is the starting point of the cycle","correct":true,"visible":false},{"text":"Inner mitochondrial membrane is permeable to it","correct":false,"visible":false},{"text":"It is toxic if present in uncontrolled amounts","correct":false,"visible":false}]},{"id":4823,"text":"Which of the following occurs during strenuous exercise?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 894.","responses":[{"text":"Anaerobic respiration occurs","correct":true,"visible":false},{"text":"Large amount of energy is produced by aerobic respiration","correct":false,"visible":false},{"text":"Heart rate drops","correct":false,"visible":false},{"text":"Frequency of Krebs cycle corresponds to breathing rate","correct":false,"visible":false},{"text":"Krebs cycle becomes faster","correct":false,"visible":false}]},{"id":4824,"text":"Which of the following is correct about the relation of the head of the pancreas with the duodenum?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 488.","responses":[{"text":"It is medial to the duodenum","correct":false,"visible":false},{"text":"It lies in the curve of duodenum","correct":true,"visible":false},{"text":"It lies posterior to the duodenum","correct":false,"visible":false},{"text":"It lies superior to the curve of duodenum","correct":false,"visible":false},{"text":"It is lateral to the duodenum","correct":false,"visible":false}]},{"id":4825,"text":"The left gastric artery originates from which of the following?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 308.","responses":[{"text":"Abdominal aorta","correct":false,"visible":false},{"text":"Superior mesenteric artery","correct":false,"visible":false},{"text":"Celiac trunk","correct":true,"visible":false},{"text":"Inferior mesenteric artery","correct":false,"visible":false},{"text":"Splenic artery","correct":false,"visible":false}]},{"id":4826,"text":"Which of the following enzymes is needed for the conversion of fumarate into malate during the Krebs cycle?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 113.","responses":[{"text":"Fumarase","correct":true,"visible":false},{"text":"Malate hydrogenase","correct":false,"visible":false},{"text":"Malate synthase","correct":false,"visible":false},{"text":"Fumarase dehydrogenase","correct":false,"visible":false},{"text":"Malate dehydrogenase","correct":false,"visible":false}]},{"id":4827,"text":"What will be the effect of high urea levels on blood sugar?","explanation":null,"reference":"Mortada I. Hyperuricemia, type 2 diabetes mellitus, and hypertension: an emerging association. Current Hypertension Reports. Published September 2017. https://pubmed.ncbi.nlm.nih.gov/28770533/","responses":[{"text":"Blood sugar level will increase","correct":true,"visible":false},{"text":"It will decrease up to a given point and then increase","correct":false,"visible":false},{"text":"Blood sugar level will decrease","correct":false,"visible":false},{"text":"There will be no affect","correct":false,"visible":false},{"text":"It will increase up to a given point and then decrease","correct":false,"visible":false}]},{"id":4834,"text":"Gastric carcinoma is associated with which one of the following factors?","explanation":null,"reference":"1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 764.\r\n\r\n2) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 104-105.","responses":[{"text":"Helicobacter pylori infection","correct":true,"visible":false},{"text":"Smoking","correct":false,"visible":false},{"text":"Non-steroidal anti-inflammatory drugs (NSAIDs)","correct":false,"visible":false},{"text":"Alcohol abuse","correct":false,"visible":false},{"text":"Escherichia coli infection","correct":false,"visible":false}]},{"id":4853,"text":"Normal gut sounds are heard approximately after how much time?","explanation":null,"reference":"Innes JA, Dover AR, Fairhurst K, Macleod J, eds. Macleod’s Clinical Examination. 14th ed. Elsevier; 2018: 110.","responses":[{"text":"1-5 seconds","correct":false,"visible":false},{"text":"15-20 seconds","correct":false,"visible":false},{"text":"10-20 seconds","correct":false,"visible":false},{"text":"5-10 seconds","correct":true,"visible":false},{"text":"1-3 minutes","correct":false,"visible":false}]},{"id":4876,"text":"Which of the following is the most common cause of gastric ulcer in antrum?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 763.","responses":[{"text":"Spicy food","correct":false,"visible":false},{"text":"Helicobacter pylori","correct":true,"visible":false},{"text":"Excessive production of pepsin","correct":false,"visible":false},{"text":"Non-steroidal anti-inflammatory drugs (NSAIDs)","correct":false,"visible":false},{"text":"Stress","correct":false,"visible":false}]},{"id":4877,"text":"Which of the following artery supplies blood to the pancreas?","explanation":"The pancreas receives its blood supply primarily from the **splenic artery**, a branch of the **celiac trunk**. The celiac trunk is a major branch of the abdominal aorta that supplies blood to various organs in the upper abdomen, including the liver, stomach, spleen, and pancreas.\r\n\r\nThe splenic artery courses along the upper border of the pancreas and then divides into multiple smaller branches within the pancreas itself. These branches form an intricate network of blood vessels that supply the various parts of the pancreas.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 491.","responses":[{"text":"Splenic artery","correct":true,"visible":false},{"text":"Inferior mesenteric artery","correct":false,"visible":false},{"text":"Inferior esophageal artery","correct":false,"visible":false},{"text":"Left gastric artery","correct":false,"visible":false},{"text":"Cystic artery","correct":false,"visible":false}]},{"id":4880,"text":"Which of the following structures is not present anterior to the kidneys?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 375.","responses":[{"text":"Pancreas","correct":false,"visible":false},{"text":"Suprarenal glands","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Splenic flexure","correct":false,"visible":false},{"text":"Hepatic flexure","correct":false,"visible":false}]},{"id":4884,"text":"Which of the following is seen in celiac disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 783.","responses":[{"text":"Villous hypertrophy","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Weight gain","correct":false,"visible":false},{"text":"Metaplasia of intestinal epithelium","correct":false,"visible":false},{"text":"Villous atrophy","correct":true,"visible":false}]},{"id":4885,"text":"An increase in SGPT (serum glutamic pyruvic transaminase) occurs in which of the following diseases?","explanation":null,"reference":"GIT and liver module; Medicine lecture slides; Topic: Liver function tests; Subtopic: SGPT in liver diseases.","responses":[{"text":"Barret's esophagus","correct":false,"visible":false},{"text":"Breast cancer","correct":false,"visible":false},{"text":"Liver disease","correct":true,"visible":false},{"text":"Renal disease","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":4933,"text":"Which of the following supplies the superior ascending colon and the right colic flexure?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 472.","responses":[{"text":"Ileocolic artery","correct":false,"visible":false},{"text":"Ileocolic artery and right colic artery","correct":false,"visible":false},{"text":"Middle colic artery","correct":false,"visible":false},{"text":"Ileocolic artery and middle colic artery","correct":false,"visible":false},{"text":"Right colic artery","correct":true,"visible":false}]},{"id":4935,"text":"In the wheel mode of disease causation, the central core represents which of the following?","explanation":null,"reference":"1) Green BN, Johnson CD. Establishing a theoretical basis for research in musculoskeletal epidemiology: a proposal for the use of biopsychosocial theory in investigations of back pain and smoking. Journal of Chiropractic Humanities. Published November 11, 2013. Accessed July 13, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4111074/\r\n\r\n2) Ilyas M. Public Health and Community Medicine. 8th ed. TIME Publisher; 2016: 84.","responses":[{"text":"Genetic makeup of host","correct":true,"visible":false},{"text":"Biological environment","correct":false,"visible":false},{"text":"Social environment","correct":false,"visible":false},{"text":"Quality of food","correct":false,"visible":false},{"text":"Disease causing agent","correct":false,"visible":false}]},{"id":4938,"text":"Which of the following enzymes is involved in the synthesis of glycerol for triglyceride synthesis?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 188-189.","responses":[{"text":"Phosphoglycerate kinase","correct":false,"visible":false},{"text":"Pyruvate kinase","correct":false,"visible":false},{"text":"Glycerol-3-phosphate dehydrogenase","correct":true,"visible":false},{"text":"Hexokinase","correct":false,"visible":false},{"text":"Glucokinase","correct":false,"visible":false}]},{"id":4939,"text":"Gastric impression on the visceral surface of the liver is formed by which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 494.","responses":[{"text":"Posterior surface of stomach","correct":false,"visible":false},{"text":"Antero-superior surface of stomach","correct":true,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Left suprarenal gland","correct":false,"visible":false},{"text":"Right suprarenal gland","correct":false,"visible":false}]},{"id":4940,"text":"In diabetes mellitus, which of the following organs is most affected?","explanation":null,"reference":"Daryabor G, Atashzar MR, Kabelitz D, Meri S, Kalantar K. The effects of type 2 diabetes mellitus on organ metabolism and the immune system. Frontiers in Immunology. Published July 22, 2020. Accessed July 13, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7387426/","responses":[{"text":"Spleen","correct":false,"visible":false},{"text":"Gall bladder","correct":false,"visible":false},{"text":"Brain","correct":false,"visible":false},{"text":"Heart","correct":false,"visible":false},{"text":"Liver","correct":true,"visible":false}]},{"id":4941,"text":"Hematoma, below the umbilicus in the rectus sheath, is due to the rupture of which of the following arteries?","explanation":null,"reference":"1) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 414, 417.\r\n\r\n\r\n2) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 288.","responses":[{"text":"Superior epigastric artery","correct":false,"visible":false},{"text":"Inferior mesenteric artery","correct":false,"visible":false},{"text":"Inferior epigastric artery","correct":true,"visible":false},{"text":"Celiac artery","correct":false,"visible":false},{"text":"Superior mesenteric artery","correct":false,"visible":false}]},{"id":4942,"text":"Which of the following is the common intermediate in carbohydrate, fat, and protein metabolism?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 109, 183, 266.","responses":[{"text":"Dihydroxyacetone phosphate","correct":false,"visible":false},{"text":"Acetyl CoA","correct":true,"visible":false},{"text":"Pyruvic acid","correct":false,"visible":false},{"text":"Succinyl CoA","correct":false,"visible":false},{"text":"Glycerate-3-phosphate","correct":false,"visible":false}]},{"id":4943,"text":"The carbon skeleton of glycerol is made from which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 188.","responses":[{"text":"Fructose","correct":false,"visible":false},{"text":"Sucrose","correct":false,"visible":false},{"text":"Carbon dioxide","correct":false,"visible":false},{"text":"Glucose","correct":true,"visible":false},{"text":"Acetyl CoA","correct":false,"visible":false}]},{"id":4944,"text":"In which of the following condition, acidosis occurs with an increase in blood sugar?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1113-1114.","responses":[{"text":"Hyperosmolar non-ketotic coma","correct":false,"visible":false},{"text":"Metabolic acidosis","correct":false,"visible":false},{"text":"Lactic acidosis","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":true,"visible":false},{"text":"Respiratory acidosis","correct":false,"visible":false}]},{"id":4945,"text":"Which of the following best explains the cause of dehydration due to increased blood sugar in diabetic patients?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1113.","responses":[{"text":"Diuresis","correct":true,"visible":false},{"text":"Insulinemia","correct":false,"visible":false},{"text":"Antidiuretic hormone","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"High osmolarity of urine","correct":false,"visible":false}]},{"id":4946,"text":"Which of the following is a lysosomal storage disease characterized by the accumulation of complex sugars in the body tissues?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 129.","responses":[{"text":"Gaucher disease","correct":false,"visible":false},{"text":"Wolman disease","correct":false,"visible":false},{"text":"Pompe's disease","correct":true,"visible":false},{"text":"Tay-Sachs disease","correct":false,"visible":false},{"text":"Niemann-Pick type C disease","correct":false,"visible":false}]},{"id":4947,"text":"Fatty acids absorbed from the intestine enter the blood in which of the following forms?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 227.","responses":[{"text":"Chylomicrons","correct":true,"visible":false},{"text":"Cholesterol","correct":false,"visible":false},{"text":"High-density lipoprotein (HDL)","correct":false,"visible":false},{"text":"Low-density lipoprotein (LDL)","correct":false,"visible":false},{"text":"Very low-density lipoprotein (VLDL)","correct":false,"visible":false}]},{"id":4949,"text":"Which of the following pathologies does not cause an increase in gamma-glutamyl transpeptidase?","explanation":null,"reference":"GIT and liver module; Medicine lecture slides; Topic: Liver function tests; Subtopic: Gamma-glutamyl transferase: enzymes in liver diseases.","responses":[{"text":"Alchohol abuse","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Bone disease","correct":true,"visible":false},{"text":"Biliary tract disease","correct":false,"visible":false},{"text":"Liver disease","correct":false,"visible":false}]},{"id":4958,"text":"Which type of study investigates the diagnosis, treatment, novel occurrence, and demographic of a patient?","explanation":null,"reference":"Guidelines to writing a clinical case report. Heart Views : The Official Journal of the Gulf Heart Association. Published 2017. Accessed July 13, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5686928/","responses":[{"text":"Meta-analysis","correct":false,"visible":false},{"text":"Case-control","correct":false,"visible":false},{"text":"Ecological study","correct":false,"visible":false},{"text":"Cohort study","correct":false,"visible":false},{"text":"Case report","correct":true,"visible":false}]},{"id":4959,"text":"What is correct regarding the blood supply of the stomach?","explanation":null,"reference":null,"responses":[{"text":"All gastric venous blood flows through short gastric veins","correct":false,"visible":false},{"text":"Short gastric arteries are branch of the splenic artery","correct":true,"visible":false},{"text":"Right gastric vein flows directly into the inferior vena cava","correct":false,"visible":false},{"text":"Left gastric veins flows directly into the left renal vein","correct":false,"visible":false},{"text":"Left gastric artery arises directly from the aorta","correct":false,"visible":false}]},{"id":4960,"text":"What is the structure of the Hepatitis C virus?","explanation":null,"reference":"Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 335.","responses":[{"text":"Double stranded DNA without envelope","correct":false,"visible":false},{"text":"Single strand RNA without envelope","correct":false,"visible":false},{"text":"Double strand RNA with envelope","correct":false,"visible":false},{"text":"Single strand RNA with envelope","correct":true,"visible":false},{"text":"Single strand DNA with envelope","correct":false,"visible":false}]},{"id":4963,"text":"The root of the mesentery is reflected off which retroperitoneal organ?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 465.","responses":[{"text":"Kidney","correct":false,"visible":false},{"text":"Right suprarenal gland","correct":false,"visible":false},{"text":"Spleen","correct":false,"visible":false},{"text":"Duodenum","correct":true,"visible":false},{"text":"Left suprarenal gland","correct":false,"visible":false}]},{"id":4965,"text":"A person is stabbed in the lower anterior abdomen. What nerve carries sensations for that region?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 416-417.","responses":[{"text":"Femoral nerve","correct":false,"visible":false},{"text":"Iliohypogastric nerve","correct":true,"visible":false},{"text":"Ilioinguinal nerve","correct":false,"visible":false},{"text":"Obturator nerve","correct":false,"visible":false},{"text":"Genitofemoral nerve","correct":false,"visible":false}]},{"id":4967,"text":"What artery supplies the jejunum?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 465.","responses":[{"text":"Superior mesenteric artery","correct":true,"visible":false},{"text":"Left colic artery","correct":false,"visible":false},{"text":"Ileocecal artery","correct":false,"visible":false},{"text":"Inferior mesenteric artery","correct":false,"visible":false},{"text":"Celiac artery","correct":false,"visible":false}]},{"id":4970,"text":"Which of the following is not an absorptive feature of the small intestine?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 315.","responses":[{"text":"Villi","correct":false,"visible":false},{"text":"Microvilli","correct":false,"visible":false},{"text":"Cilia","correct":true,"visible":false},{"text":"Brush border","correct":false,"visible":false},{"text":"Valves of  Kerckring","correct":false,"visible":false}]},{"id":4971,"text":"A drug is used to inhibit complex 1 of the electron transport chain. What pathway is inhibited?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 74-75.","responses":[{"text":"NADH to NAD+","correct":true,"visible":false},{"text":"FADH2 to FAD+","correct":false,"visible":false},{"text":"ADP + Pi to ATP","correct":false,"visible":false},{"text":"FMN to FeS","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":4972,"text":"Travellers are most commonly affected by what hepatitis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 119.","responses":[{"text":"Hepatitis D","correct":false,"visible":false},{"text":"Hepatitis E","correct":false,"visible":false},{"text":"Hepatitis C","correct":false,"visible":false},{"text":"Hepatitis B","correct":false,"visible":false},{"text":"Hepatitis A","correct":true,"visible":false}]},{"id":4994,"text":"How many centimeters do you insert a nasogastric tube?","explanation":null,"reference":"Sigmon DF, An J. Nasogastric tube. In: StatPearls. StatPearls Publishing; 2022. Accessed July 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK556063/","responses":[{"text":"28 cm","correct":false,"visible":false},{"text":"16 cm","correct":false,"visible":false},{"text":"40 cm","correct":false,"visible":false},{"text":"56 cm","correct":true,"visible":false},{"text":"100 cm","correct":false,"visible":false}]},{"id":6081,"text":"Which of the following correctly describes the glycemic index?","explanation":"The **glycemic index (GI)** is defined as the **ability of food to increase blood glucose levels** when compared to a reference carbohydrate, typically glucose or white bread. Foods with a high GI are rapidly digested and absorbed, leading to a quicker and larger increase in blood glucose levels, while foods with a low GI are digested and absorbed more slowly, resulting in a slower and smaller increase in blood glucose levels.","reference":"(1) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 366.\r\n\r\n\r\n(2) Vlachos D, Malisova S, Lindberg FA, Karaniki G. Glycemic index (Gi) or glycemic load (Gl) and dietary interventions for optimizing postprandial hyperglycemia in patients with t2 diabetes: a review. Nutrients. Published May 27, 2020. Accessed August 7, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7352659/","responses":[{"text":"The ability of the liver to maintain blood glucose levels","correct":false,"visible":false},{"text":"The ability of food to reduce blood glucose levels","correct":false,"visible":false},{"text":"The ability of food to increase blood glucose levels","correct":true,"visible":false},{"text":"The ability of the liver to increase blood glucose levels","correct":false,"visible":false},{"text":"The ability of the liver to reduce blood glucose levels","correct":false,"visible":false}]},{"id":9360,"text":"Which of the following is the rate-limiting enzyme in cholesterol synthesis?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 221.","responses":[{"text":"Mevalonate carboxylase","correct":false,"visible":false},{"text":"Prenyl transferase","correct":false,"visible":false},{"text":"Squalene synthase","correct":false,"visible":false},{"text":"HMG-CoA synthase","correct":false,"visible":false},{"text":"HMG-CoA reductase","correct":true,"visible":false}]}
]

